		userId: string,
		permissionData: any,
	): Promise<{ id: string } | null> {
		return await this.prisma.user.findFirst({
			select: { id: true },
			where: {
				id: userId,
				roles: {
					some: {
						permissions: {
							some: {
								...permissionData,
								access: permissionData.access
									? { in: permissionData.access }
									: undefined,
							},
						},
					},
				},
			},
		})
	}

Here's the equivalent query using Drizzle ORM, assuming you have the corresponding schema defined with similar relations between users, roles, and permissions:

```typescript
async checkUserPermission(
  userId: string,
  permissionData: any,
): Promise<{ id: string } | null> {
  const query = db
    .select({ id: users.id })
    .from(users)
    .leftJoin(usersToRoles, eq(users.id, usersToRoles.userId))
    .leftJoin(roles, eq(usersToRoles.roleId, roles.id))
    .leftJoin(rolesToPermissions, eq(roles.id, rolesToPermissions.roleId))
    .leftJoin(permissions, eq(rolesToPermissions.permissionId, permissions.id))
    .where(
      and(
        eq(users.id, userId),
        // Add additional permission conditions based on permissionData
        ...(permissionData.access 
          ? [inArray(permissions.access, permissionData.access)]
          : []),
        // Add other permission conditions from permissionData
        ...Object.entries(permissionData)
          .filter(([key]) => key !== 'access')
          .map(([key, value]) => eq(permissions[key as keyof typeof permissions], value))
      )
    )
    .limit(1);

  const result = await query;
  return result.length > 0 ? { id: result[0].id } : null;
}
```

Note that this assumes you have your schema defined something like this:

```typescript
const users = pgTable('users', {
  id: text('id').primaryKey(),
  // other user fields
});

const roles = pgTable('roles', {
  id: text('id').primaryKey(),
  // other role fields
});

const permissions = pgTable('permissions', {
  id: text('id').primaryKey(),
  access: text('access'),
  // other permission fields
});

const usersToRoles = pgTable('users_to_roles', {
  userId: text('user_id').references(() => users.id),
  roleId: text('role_id').references(() => roles.id),
});

const rolesToPermissions = pgTable('roles_to_permissions', {
  roleId: text('role_id').references(() => roles.id),
  permissionId: text('permission_id').references(() => permissions.id),
});
```

The main differences from the Prisma query are:

1. Drizzle requires explicit join statements instead of Prisma's nested relation queries
2. The conditions need to be explicitly combined using `and()`
3. Array conditions use `inArray()` instead of Prisma's `in`
4. The joins are written out explicitly rather than using Prisma's `some` relation filters

You might need to adjust the exact table and column names to match your schema, but this should give you the equivalent functionality.
